<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mpstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -P</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ALL</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # 每核使用率,含 %irq / %soft</span></span>
